  '2026-04-10',
  '',
  '[{"name":"SAP Business One","activities":[{"id":"ac1094b0-4f58-476a-8df9-5c9021c95ed0","title":"Restrição de Acesso ao Campo de Desconto","activity":"Desativação do campo de desconto geral nos documentos de venda via configurações de interface.","highlight":"A restrição via código interno foi removida para priorizar o controle nativo por perfil de usuário.","called":"","projectTeam":[],"cycleImplantation":"","cycleTime":"","benefit":"Inativação do campo [Desconto], no desconto geral do documento","difficulty":"","category":"","position":1},{"id":"a9a1e5fe-99cf-4fd4-86a5-e42c083365d9","title":"Padronização de Interfaces de Usuário","activity":"Restauração e configuração das telas padrão para todos os usuários do sistema.","highlight":"Correção de instabilidade visual identificada em 09/04, garantindo a uniformidade operacional.","called":"","projectTeam":[],"cycleImplantation":"","cycleTime":"","benefit":"Reconfigurado o layout padrão de cada usuário do sistema.","difficulty":"","category":"","position":2},{"id":"8202a094-9bb0-47e3-9503-3269d8ee97d3","title":"Automatização de Descrições Contábeis","activity":"Ajuste no preenchimento automático das observações do diário em Notas Fiscais de Saída.","highlight":"","called":"","projectTeam":[],"cycleImplantation":"","cycleTime":"","benefit":"Correção da descrição automática, gerada por consulta, na Nota Fiscal de Saída.","difficulty":"","category":"","position":3}]},{"name":"Shop Control 9","activities":[]},{"name":"Queries (Consultas)","activities":[{"id":"a83d7108-9e1d-4485-b75b-9814d8082728","title":"Relatório de Movimentação de Estoque","activity":"Implementação de colunas distintas para visualização de entradas e saídas por transferência.","highlight":"","called":"418219","projectTeam":[],"cycleImplantation":"","cycleTime":"","benefit":"Adicionado consulta de Saída e Entrada de Transferência de Estoque.","difficulty":"","category":"","position":1},{"id":"79a1bdf8-2b46-4585-8e68-ff077d3bf164","title":"Detalhamento de Fretes e Despesas em Notas Fiscais","activity":"Inclusão de valores de frete (total e rateado por item) e despesas acessórias nos relatórios de saída e entrega.","highlight":"","called":"416863","projectTeam":[],"cycleImplantation":"","cycleTime":"","benefit":"Adicionado valor total de frete, valor fracionado por item e Outras despesas.","difficulty":"","category":"","position":2}]},{"name":"Banco de Dados (BD)","activities":[{"id":"087b1564-a387-4731-a2e2-614a9fcda07b","title":"Melhoria em Regras de Validação do Sistema","activity":"Atualização das regras de preenchimento para Cadastros de Itens, Parceiros de Negócios e Notas de Saída.","highlight":"Em fase final de testes para validação de segurança. A implementação oficial ocorrerá após homologação.","called":"","projectTeam":[],"cycleImplantation":"","cycleTime":"","benefit":"Aperfeiçoando a escrita das consultas, condições, descrição dos bloqueios e comentários.","difficulty":"","category":"","position":2}]},{"name":"Manutencao de Maquinas","activities":[]},{"name":"Treinamentos","activities":[]},{"name":"Roadmap de Acoes e Melhoria Continua","activities":[{"id":"b61e84d0-ea80-4d6e-a0c4-13cea4d29dc5","title":"Otimização de Regras Internas","activity":"Redução no tempo modificações e quantidade dos bloqueios e melhora na utilização do sistema.","highlight":"","called":"","projectTeam":[],"cycleImplantation":"","cycleTime":"","benefit":"Aumento da performance do sistema e maior agilidade na manutenção de regras de negócio, reduzindo interrupções operacionais.","difficulty":"low","category":"Infraestrutura","position":1},{"id":"7db91aab-49e0-4208-9d08-b077dd06c751","title":"Padronização de Interfaces","activity":"Otimização operacional, adaptando o espaço às necessidades únicas de cada equipe para aumentar a produtividade e reduzir desperdícios","highlight":"","called":"","projectTeam":[],"cycleImplantation":"","cycleTime":"","benefit":"Telas adaptadas às necessidades de cada equipe, eliminando distrações e aumentando a velocidade na execução de tarefas diárias.","difficulty":"medium","category":"Processos","position":2},{"id":"e990c854-96f5-4ca5-85be-8c91582e1c04","title":"Gestão Centralizada de Acessos","activity":"Otimização na manutenção de acessos e redução de retrabalho na liberação para cada usuário do sistema.","highlight":"","called":"","projectTeam":[],"cycleImplantation":"","cycleTime":"","benefit":"Maior segurança e agilidade no controle de permissões, eliminando o retrabalho na liberação de novos usuários e funções.","difficulty":"medium","category":"Processos","position":3}]}]'::jsonb
